WHERE 1=1

/*대상 검색*/

    AND bi.HDQR_BOB_DCD = #{searchTarget}


/*일자 검색*/

    AND bi.BASE_YM BETWEEN REPLACE(#{searchStartDate}, '.', '') AND REPLACE(#{searchEndDate}, '.', '')

WHERE 1=1

/*대상 검색*/

    AND ci.HDQR_BOB_DCD = #{searchTarget}


/*일자 검색*/

    AND ci.TSTM_YMD BETWEEN REPLACE(#{searchStartDate}, '.', '') AND REPLACE(#{searchEndDate}, '.', '')
